+  for (const envName of [
+    ...fixture.env,
+    ...(params.manifest.providers[fixture.provider]?.env ?? []),
+  ]) {
+    if (!process.env[envName]) {
+      return {
+        diagnostics: [`missing env: ${envName}`],
+        failureKind: "config",
