+    results,
+    totalPassed: results.filter((entry) => entry.ok).length,
+  };
+}
+
+export function computeExitCode(result: CommandRunResult | SuiteRunResult): number {
+  if ("results" in result) {
+    const failure = result.results.find((entry) => !entry.ok);
+    return failure ? computeExitCode(failure) : 0;
+  }
+
+  if (result.ok) {
+    return 0;
+  }
+
+  switch (result.failureKind) {
+    case "auth":
+      return 11;
+    case "config":
+      return 10;
+    case "connectivity":
+      return 12;
+    case "outbound":
+      return 13;
+    case "inbound":
+      return 14;
+    case "timeout":
+      return 15;
+    case "assertion":
+      return 16;
+    default:
+      return 1;
+  }
+}
+
+function toFailure(
+  fixtureId: string,
+  providerId: string,
+  mode: string,
+  error: unknown,
+  nonce?: string,
+): CommandRunResult {
+  const diagnostics = [ensureErrorMessage(error)];
+  if (error instanceof MultipassError) {
+    return {
+      diagnostics,
+      failureKind: error.kind,
+      fixtureId,
+      mode,
+      nonce,
+      ok: false,
+      providerId,
+    };
+  }
+
+  return {
+    diagnostics,
+    failureKind: "assertion",
+    fixtureId,
+    mode,
+    nonce,
+    ok: false,
+    providerId,
+  };
+}

